// ============================================================================
// LOAD BRAND MEMORY - Analyst MCP V5 (Cloud Native)
// ============================================================================

return [{
  json: {
    brand_id: "ak_v5_demo",

    objectives: {
      primary_kpi: "ROAS",
      target_values: {
        roas: 4.0,
        cpa: 25.0,
        conversion_rate: 2.5,
        aov: 120,
        ltv: 350,
        cac_ltv_ratio: 0.15
      },
      alert_thresholds: {
        roas_critical: 2.0,
        roas_warning: 3.0,
        cpa_critical: 40,
        cpa_warning: 30,
        cvr_critical: 1.0,
        cvr_warning: 1.8,
        anomaly_threshold_pct: 20
      }
    },

    priorities: {
      tier_1: ["ROAS", "Margin", "Net Revenue"],
      tier_2: ["CPA", "CAC", "Conversion Rate"],
      tier_3: ["Traffic", "Impressions", "CTR"]
    },

    comparison_periods: {
      default: "WoW",
      available: ["DoD", "WoW", "MoM", "YoY", "vs_target"]
    }
  }
}];

// ============================================================================
// LOAD STRATEGY - Analyst MCP V5 (Cloud Native)
// ============================================================================

return [{
  json: {
    active_campaigns: [
      { id: "camp_search_generic", name: "Search_Generic", platform: "google", type: "search", status: "active", daily_budget: 150, priority: "high" },
      { id: "camp_display_retargeting", name: "Display_Retargeting", platform: "google", type: "display", status: "active", daily_budget: 80, priority: "medium" },
      { id: "camp_meta_prospecting", name: "Meta_Prospecting", platform: "meta", type: "conversions", status: "active", daily_budget: 200, priority: "high" },
      { id: "camp_meta_retargeting", name: "Meta_Retargeting", platform: "meta", type: "conversions", status: "active", daily_budget: 100, priority: "high" }
    ],

    market_context: {
      seasonality: "High",
      seasonality_factor: 1.3,
      competitor_move: "Aggressive",
      market_trend: "Growing",
      active_events: [
        { name: "Soldes Hiver", impact: "high", end_date: "2025-02-15" },
        { name: "Concurrent promo -30%", impact: "medium", detected: "2025-01-28" }
      ],
      industry_benchmarks: { roas: 3.5, cpa: 28, cvr: 2.2, ctr: 1.8 }
    },

    historical_baselines: {
      last_7d_avg: { roas: 3.8, cpa: 26.5, cvr: 2.3, daily_spend: 520, daily_revenue: 1976 },
      last_30d_avg: { roas: 3.6, cpa: 27.8, cvr: 2.2, daily_spend: 480, daily_revenue: 1728 }
    }
  }
}];

// ============================================================================
// PREPARE ANALYST CONTEXT - Merge all inputs
// ============================================================================

const brandMemory = $('Load Brand Memory').item.json;
const strategy = $('Load Strategy').item.json;
const userInput = $('Webhook Trigger').item.json;

// Detect if image is attached
const hasImage = !!(userInput.body?.image || userInput.body?.imageBase64 || userInput.image || userInput.imageBase64);
const imageData = userInput.body?.image || userInput.body?.imageBase64 || userInput.image || userInput.imageBase64 || null;

// Get project_id from input
const projectId = userInput.body?.project_id || userInput.project_id || userInput.body?.shared_memory?.project_id || null;

return [{
  json: {
    user_request: {
      message: userInput.body?.message || userInput.message || userInput.body?.chatInput || userInput.chatInput || "Analyse mes performances",
      session_id: userInput.body?.session_id || `session_${Date.now()}`,
      requested_metrics: userInput.body?.metrics || null,
      date_range: userInput.body?.date_range || "last_7d",
      timestamp: new Date().toISOString(),
      project_id: projectId
    },
    brand: brandMemory,
    strategy: strategy,
    has_image: hasImage,
    image_data: imageData,
    analysis_config: {
      comparison_period: "WoW",
      include_anomaly_detection: true,
      anomaly_threshold: brandMemory.objectives.alert_thresholds.anomaly_threshold_pct,
      priority_metrics: brandMemory.priorities.tier_1
    }
  }
}];

// ============================================================================
// DATA FETCHER: GA4 + GSC (Production: remplacer par vrais appels API)
// ============================================================================
// Cette version DETECTE si les donnees sont vides/absentes
// ============================================================================

const context = $input.first().json;
const userInput = $('Webhook Trigger').item.json;

// ─────────────────────────────────────────────────────────────────────────
// DETECTION: L'utilisateur a-t-il connecte ses comptes?
// En production: verifier si les credentials GA4/GSC existent
// ─────────────────────────────────────────────────────────────────────────
const hasGA4Connected = userInput.body?.ga4_connected === true || userInput.ga4_connected === true;
const hasGSCConnected = userInput.body?.gsc_connected === true || userInput.gsc_connected === true;

// Si pas de connexion, retourner des donnees vides avec flag
if (!hasGA4Connected && !hasGSCConnected) {
  return [{
    json: {
      data_status: "NO_DATA_AVAILABLE",
      ga4: null,
      gsc: null,
      context: context,
      message_for_ai: "AUCUNE DONNEE DISPONIBLE. L'utilisateur n'a pas connecte GA4 ni GSC. Tu dois lui demander de connecter ses comptes ou de te fournir ses chiffres manuellement."
    }
  }];
}

// ─────────────────────────────────────────────────────────────────────────
// SI DONNEES DISPONIBLES: Simuler les metriques (en prod: vrais appels API)
// ─────────────────────────────────────────────────────────────────────────

function generateRealisticMetrics(baseline, variance = 0.15) {
  const factor = 1 + (Math.random() - 0.5) * 2 * variance;
  return Math.round(baseline * factor * 100) / 100;
}

const currentPeriod = {
  sessions: generateRealisticMetrics(12500, 0.1),
  users: generateRealisticMetrics(9800, 0.1),
  new_users: generateRealisticMetrics(6200, 0.12),
  pageviews: generateRealisticMetrics(38000, 0.08),
  avg_session_duration: generateRealisticMetrics(185, 0.15),
  bounce_rate: generateRealisticMetrics(42, 0.1),
  transactions: generateRealisticMetrics(285, 0.12),
  revenue: generateRealisticMetrics(34200, 0.15),
  conversion_rate: generateRealisticMetrics(2.28, 0.1),
  avg_order_value: generateRealisticMetrics(120, 0.08),
  ad_spend: generateRealisticMetrics(3640, 0.05),
  ad_clicks: generateRealisticMetrics(4850, 0.1),
  ad_impressions: generateRealisticMetrics(285000, 0.1),
  ctr: generateRealisticMetrics(1.7, 0.1),
  cpc: generateRealisticMetrics(0.75, 0.08)
};

const previousPeriod = {
  sessions: 11800, users: 9200, new_users: 5800, pageviews: 35500,
  avg_session_duration: 178, bounce_rate: 44, transactions: 265,
  revenue: 31500, conversion_rate: 2.24, avg_order_value: 118.9,
  ad_spend: 3500, ad_clicks: 4600, ad_impressions: 270000, ctr: 1.7, cpc: 0.76
};

const calculated = {
  roas: Math.round((currentPeriod.revenue / currentPeriod.ad_spend) * 100) / 100,
  roas_previous: Math.round((previousPeriod.revenue / previousPeriod.ad_spend) * 100) / 100,
  cpa: Math.round((currentPeriod.ad_spend / currentPeriod.transactions) * 100) / 100,
  cpa_previous: Math.round((previousPeriod.ad_spend / previousPeriod.transactions) * 100) / 100,
  gross_margin: Math.round(currentPeriod.revenue * 0.40),
  net_profit: Math.round(currentPeriod.revenue * 0.40 - currentPeriod.ad_spend),
  profit_margin_pct: Math.round(((currentPeriod.revenue * 0.40 - currentPeriod.ad_spend) / currentPeriod.revenue) * 10000) / 100
};

const gscData = {
  summary: { total_clicks: 8450, total_impressions: 245000, average_ctr: 3.45, average_position: 12.8, clicks_change_pct: 5.2, impressions_change_pct: 8.1, position_change: -0.8 },
  top_queries: [
    { query: "agence marketing ia", clicks: 420, impressions: 8500, ctr: 4.94, position: 3.2 },
    { query: "automatisation marketing", clicks: 380, impressions: 12000, ctr: 3.17, position: 5.8 }
  ]
};

const sparklines = {
  revenue: [4200, 4800, 5100, 4600, 5300, 4900, 5300],
  roas: [3.6, 3.8, 4.1, 3.9, 4.2, 4.0, 4.3],
  sessions: [1650, 1780, 1820, 1700, 1890, 1750, 1910],
  transactions: [38, 42, 45, 40, 46, 43, 47]
};

return [{
  json: {
    data_status: "DATA_AVAILABLE",
    ga4: {
      source: "ga4_mock",
      current_period: currentPeriod,
      previous_period: previousPeriod,
      calculated_kpis: calculated,
      sparklines: sparklines
    },
    gsc: gscData,
    context: context,
    message_for_ai: "DONNEES DISPONIBLES. Analyse les metriques GA4 et GSC fournies. Applique les regles Senior: scepticisme si variation >20%, contexte WoW obligatoire, Business First (ROAS/Marge avant Traffic)."
  }
}];

