// ============================================================================
// FORMAT UI RESPONSE - Analyst MCP V5.1
// ============================================================================
// Parse la sortie de l'AI Agent et genere la reponse UI finale
// ============================================================================

const aiOutput = $input.first().json;
let analysisData;

// ─────────────────────────────────────────────────────────────────────────
// PARSE AI OUTPUT (peut etre string ou object)
// ─────────────────────────────────────────────────────────────────────────
try {
  if (typeof aiOutput.output === 'string') {
    // Nettoyer le JSON (enlever ```json si present)
    let cleanOutput = aiOutput.output
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();
    analysisData = JSON.parse(cleanOutput);
  } else if (aiOutput.output && typeof aiOutput.output === 'object') {
    analysisData = aiOutput.output;
  } else if (aiOutput.analysis_result) {
    analysisData = aiOutput;
  } else {
    throw new Error('Format de sortie non reconnu');
  }
} catch (e) {
  // Fallback si parsing echoue
  analysisData = {
    analysis_result: {
      global_status: 'waiting_for_data',
      global_tone: 'neutral',
      insights: [{ type: 'warning', message: 'Erreur de parsing de la reponse IA', action: 'Reessayez' }],
      kpi_evaluations: {},
      sparklines: {}
    },
    chat_message: {
      content: aiOutput.output || 'Une erreur s\'est produite lors de l\'analyse.',
      follow_up_questions: ['Pouvez-vous reformuler votre question?']
    },
    context: { data_status: 'ERROR', analysis_type: 'error' }
  };
}

const result = analysisData.analysis_result || {};
const chatMsg = analysisData.chat_message || {};
const ctx = analysisData.context || {};

// ─────────────────────────────────────────────────────────────────────────
// BUILD UI COMPONENTS (seulement si donnees disponibles)
// ─────────────────────────────────────────────────────────────────────────

const uiComponents = [];

if (result.global_status !== 'waiting_for_data' && result.global_status !== 'theoretical_response') {
  const kpis = result.kpi_evaluations || {};
  const sparklines = result.sparklines || {};

  // KPI Cards
  if (kpis.roas) {
    uiComponents.push({
      type: 'KPI_CARD',
      data: {
        title: 'ROAS',
        value: kpis.roas.value,
        formatted_value: `${kpis.roas.value}x`,
        unit: 'x',
        trend: kpis.roas.change_pct ? {
          direction: kpis.roas.change_pct > 0 ? 'up' : 'down',
          value: Math.abs(kpis.roas.change_pct),
          period: 'vs 7j',
          is_positive: kpis.roas.change_pct > 0
        } : null,
        sparkline: sparklines.roas || null,
        status: kpis.roas.status || 'neutral'
      },
      layout: { width: 'quarter', order: 1 }
    });
  }

  if (kpis.revenue) {
    uiComponents.push({
      type: 'KPI_CARD',
      data: {
        title: 'Revenue',
        value: kpis.revenue.value,
        formatted_value: `${kpis.revenue.value.toLocaleString('fr-FR')} EUR`,
        unit: 'EUR',
        trend: kpis.revenue.change_pct ? {
          direction: kpis.revenue.change_pct > 0 ? 'up' : 'down',
          value: Math.abs(kpis.revenue.change_pct),
          period: 'vs 7j',
          is_positive: kpis.revenue.change_pct > 0
        } : null,
        sparkline: sparklines.revenue || null,
        status: kpis.revenue.status || 'neutral'
      },
      layout: { width: 'quarter', order: 2 }
    });
  }

  if (kpis.net_profit) {
    uiComponents.push({
      type: 'KPI_CARD',
      data: {
        title: 'Profit Net',
        value: kpis.net_profit.value,
        formatted_value: `${kpis.net_profit.value.toLocaleString('fr-FR')} EUR`,
        unit: 'EUR',
        trend: null,
        sparkline: null,
        status: kpis.net_profit.status || 'neutral'
      },
      layout: { width: 'quarter', order: 3 }
    });
  }

  if (kpis.cpa) {
    uiComponents.push({
      type: 'KPI_CARD',
      data: {
        title: 'CPA',
        value: kpis.cpa.value,
        formatted_value: `${kpis.cpa.value.toLocaleString('fr-FR')} EUR`,
        unit: 'EUR',
        trend: kpis.cpa.change_pct ? {
          direction: kpis.cpa.change_pct > 0 ? 'up' : 'down',
          value: Math.abs(kpis.cpa.change_pct),
          period: 'vs 7j',
          is_positive: kpis.cpa.change_pct < 0 // CPA: moins = mieux
        } : null,
        sparkline: null,
        status: kpis.cpa.status || 'neutral'
      },
      layout: { width: 'quarter', order: 4 }
    });
  }

  // Charts si sparklines disponibles
  if (sparklines.revenue && sparklines.revenue.length > 0) {
    uiComponents.push({
      type: 'CHART_WIDGET',
      data: {
        title: 'Revenue Trend (7 derniers jours)',
        chart_type: 'area',
        data: {
          labels: ['J-6', 'J-5', 'J-4', 'J-3', 'J-2', 'J-1', 'Aujourd\'hui'],
          datasets: [{ label: 'Revenue', data: sparklines.revenue, color: '#10B981' }]
        },
        options: { show_legend: true, show_grid: true, stacked: false }
      },
      layout: { width: 'half', order: 5 }
    });
  }
}

// Action buttons (toujours present)
uiComponents.push({
  type: 'ACTION_BUTTONS',
  data: {
    layout: 'horizontal',
    actions: result.global_status === 'waiting_for_data' ? [
      { id: 'connect_ga4', label: 'Connecter GA4', icon: 'link', action_type: 'navigate', variant: 'primary', payload: { view: 'integrations' } },
      { id: 'manual_input', label: 'Entrer manuellement', icon: 'edit', action_type: 'navigate', variant: 'secondary', payload: { view: 'manual_data' } }
    ] : [
      { id: 'drill_down', label: 'Detail par campagne', icon: 'table', action_type: 'navigate', variant: 'secondary', payload: { view: 'campaign_breakdown' } },
      { id: 'export', label: 'Exporter rapport', icon: 'download', action_type: 'download', variant: 'secondary', payload: { format: 'pdf' } }
    ]
  },
  layout: { width: 'full', order: 10 }
});

// ─────────────────────────────────────────────────────────────────────────
// FINAL RESPONSE
// ─────────────────────────────────────────────────────────────────────────

const uiResponse = {
  thought_process: {
    step: 'Data Analysis Complete',
    reasoning: `Status: ${result.global_status}. ${result.insights?.length || 0} insights generes.`,
    tools_used: ['ga4_fetcher', 'gsc_fetcher', 'ai_analyst', 'vision_ai', 'check_integrations'],
    data_sources: ctx.data_status === 'DATA_AVAILABLE' ? ['Google Analytics 4', 'Google Search Console'] : [],
    confidence: result.global_status === 'waiting_for_data' ? 1.0 : 0.9,
    persona_context: 'analyst_v5'
  },

  chat_message: {
    content: chatMsg.content || 'Analyse terminee.',
    tone: result.global_tone || 'neutral',
    follow_up_questions: chatMsg.follow_up_questions || []
  },

  ui_components: uiComponents,

  meta: {
    agent_id: 'analyst',
    agent_version: 'v5.1-vision',
    timestamp: new Date().toISOString(),
    request_id: `req_analyst_${Date.now()}`,
    data_status: ctx.data_status,
    analysis_type: ctx.analysis_type
  }
};

return [{ json: uiResponse }];
